The `desktop.nix` module is intended to be a common GUI environment profile, but it contains hardcoded Nvidia-specific environment variables and a forced `LD_LIBRARY_PATH`. This violates the "separation of concerns" goal of this PR and will likely cause issues on non-Nvidia hosts (such as the `johnny-walker` VM) that import this module. These variables should be made conditional based on the presence of Nvidia drivers in the host configuration.

```
    XDG_SESSION_TYPE = "wayland";
  } // lib.optionalAttrs (lib.elem "nvidia" (config.services.xserver.videoDrivers or [ ])) {
    LIBVA_DRIVER_NAME = "nvidia";
    GBM_BACKEND = "nvidia-drm";
    __GLX_VENDOR_LIBRARY_NAME = "nvidia";
    LD_LIBRARY_PATH = lib.mkForce (
      let
        openGLPath = "/run/opengl-driver/lib";
        pipewireJackPath = lib.makeLibraryPath [ pkgs.pipewire.jack ];
      in
      if config.services.pipewire.jack.enable then "${pipewireJackPath}:${openGLPath}" else openGLPath
    );
  }
